+function trackingGroupsMatchPairs(query: QueryInstance, eid: number): boolean {
+    for (const group of query.trackingGroups) {
+        if (!group.pairTrackers.length) continue;
+        const matches = group.pairTrackers.map((tracker) => {
+            const events = tracker.events.get(eid);
