+function recordPairEvent(
+    query: QueryInstance,
+    entity: Entity,
+    trait: Trait,
+    target: Entity,
+    eventType: EventType
+): boolean {
+    const eid = getEntityId(entity);
+    let affected = false;
+    for (const group of query.trackingGroups) {
+        for (const tracker of group.pairTrackers) {
+            if (!pairMatches(tracker.pair, trait, target)) continue;
+            affected = true;
+            let events = tracker.events.get(eid);
+            if (!events) tracker.events.set(eid, (events = new Map()));
+            const previous = events.get(target);
+            // Opposite events in the same observation window cancel for this target.
+            if (previous && previous !== eventType) events.delete(target);
+            else events.set(target, eventType);
+        }
+    }
+    return affected;
